<?php
namespace App\Modules\Hr\Performance\Models;
use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
class HrPerformanceGoal extends Model { use BelongsToLegalEntity; protected $fillable=['legal_entity_id','cycle_id','employee_id','type','title','description','metric_unit','baseline_value','target_value','current_value','weight','status','created_by']; protected function casts():array{return ['baseline_value'=>'decimal:2','target_value'=>'decimal:2','current_value'=>'decimal:2','weight'=>'decimal:2'];} public function cycle():BelongsTo{return $this->belongsTo(HrPerformanceCycle::class,'cycle_id');} public function employee():BelongsTo{return $this->belongsTo(HrEmployee::class);} public function getProgressAttribute():float{$span=(float)$this->target_value-(float)$this->baseline_value;if(abs($span)<0.0001)return (float)$this->current_value>=(float)$this->target_value?100:0;return round(max(0,min(100,((float)$this->current_value-(float)$this->baseline_value)/$span*100)),1);} }
